        {
            SerializedProperty element = reorderableList.serializedProperty.GetArrayElementAtIndex(index);
            SerializedProperty nameProp = element.FindPropertyRelative("name");
            SerializedProperty tempProp = element.FindPropertyRelative("temperature");
            SerializedProperty moistProp = element.FindPropertyRelative("moisture");

            rect.y += 2;
            rect.height = EditorGUIUtility.singleLineHeight;

            // Draw name field
            Rect nameRect = new Rect(rect.x, rect.y, rect.width * 0.3f, rect.height);
            EditorGUI.PropertyField(nameRect, nameProp, GUIContent.none);

            // Draw temperature field
            Rect tempRect = new Rect(rect.x + rect.width * 0.3f, rect.y, rect.width * 0.35f, rect.height);
            EditorGUI.PropertyField(tempRect, tempProp, new GUIContent("Temp"));

            // Draw moisture field
